/**
 * C# / .NET Generator — Generates C# type definitions for the
 * `Microsoft.AgentHostProtocol.Abstractions` package from the
 * TypeScript source of truth parsed via ts-morph.
 *
 * Output: clients/dotnet/src/AgentHostProtocol.Abstractions/Generated/
 *   {State,Actions,Commands,Notifications,Errors,Messages,Version}.generated.cs
 *
 * Mirrors the structure of `generate-go.ts` — the curated struct / enum /
 * union lists are identical because they are protocol-driven, not
 * language-driven. Only the emit functions differ. The generated files
 * are always overwritten; the hand-written files under `Common/` and the
 * interface seams (`ITransport`, `IAhpSerializer`) are left alone.
 *
 * Conventions:
 *   - Wire field names (camelCase) are preserved exactly via
 *     `[JsonPropertyName("...")]`. C# property identifiers are PascalCase.
 *   - Required fields → non-nullable, always serialized.
 *   - Optional fields → nullable (`T?`) + `[JsonIgnore(Condition =
 *     JsonIgnoreCondition.WhenWritingNull)]`.
 *   - TS `number` → C# `long` unless `@format float` → `double`.
 *   - TS `unknown` / `object` → `JsonElement`; `Record<string, unknown>`
 *     → `Dictionary<string, JsonElement>`.
 *   - Discriminated unions are emitted as a sealed wrapper class deriving
 *     from `AhpUnion` (a hand-written base carrying `object? Value`) plus
 *     a generated `UnionConverter<T>` subclass. Unknown discriminator
 *     values surface as a raw `JsonElement` stored in `Value`, preserved
 *     verbatim for loss-free round-trips.
 *   - String enums map wire values via `[WireValue("...")]` + the
 *     hand-written `WireEnumConverter<T>`. Bitset enums (numeric values)
 *     become `[Flags] enum : uint` and serialize as their numeric value
 *     (System.Text.Json default), so unknown future bits round-trip.
 */

import {
  Project,
  InterfaceDeclaration,
  EnumDeclaration,
  PropertySignature,
} from 'ts-morph';
import fs from 'fs';
import path from 'path';
import { findProtocolSourceFiles } from './find-protocol-sources.js';
import { readProtocolVersions } from './read-protocol-versions.js';

const NAMESPACE = 'Microsoft.AgentHostProtocol';

function fileHeader(extraUsings: string[] = []): string {
  const usings = [
    'using System;',
    'using System.Collections.Generic;',
    'using System.Text.Json;',
    'using System.Text.Json.Serialization;',
    ...extraUsings,
  ];
  return (
    '// <auto-generated>\n' +
    '// Generated from types/*.ts — do not edit.\n' +
    '//\n' +
    '// Regenerate with: npm run generate:dotnet\n' +
    '// </auto-generated>\n' +
    '#nullable enable\n\n' +
    usings.join('\n') +
    '\n\n' +
    `namespace ${NAMESPACE};\n`
  );
}

// ─── Name Mapping ────────────────────────────────────────────────────────────

/** Strips the I prefix from interface names: IRootState → RootState */
function stripIPrefix(tsName: string): string {
  if (
    tsName.length > 1 &&
    tsName[0] === 'I' &&
    tsName[1] === tsName[1].toUpperCase() &&
    tsName[1] !== tsName[1].toLowerCase()
  ) {
    return tsName.substring(1);
  }
  return tsName;
}

const CS_RESERVED = new Set([
  'abstract', 'as', 'base', 'bool', 'break', 'byte', 'case', 'catch', 'char',
  'checked', 'class', 'const', 'continue', 'decimal', 'default', 'delegate',
  'do', 'double', 'else', 'enum', 'event', 'explicit', 'extern', 'false',
  'finally', 'fixed', 'float', 'for', 'foreach', 'goto', 'if', 'implicit',
  'in', 'int', 'interface', 'internal', 'is', 'lock', 'long', 'namespace',
  'new', 'null', 'object', 'operator', 'out', 'override', 'params', 'private',
  'protected', 'public', 'readonly', 'ref', 'return', 'sbyte', 'sealed',
  'short', 'sizeof', 'stackalloc', 'static', 'string', 'struct', 'switch',
  'this', 'throw', 'true', 'try', 'typeof', 'uint', 'ulong', 'unchecked',
  'unsafe', 'ushort', 'using', 'virtual', 'void', 'volatile', 'while',
]);

/** Escape a C# identifier that collides with a keyword via the `@` prefix. */
function csIdent(name: string): string {
  return CS_RESERVED.has(name) ? `@${name}` : name;
}

/** camelCase/snake_case/whatever → PascalCase. */
function toPascalCase(name: string): string {
  if (!name) return name;
  const cleaned = name.replace(/^_+/, '');
  const segments = cleaned.split(/[_-]/).filter(Boolean);
  if (segments.length > 1) {
    return segments.map((s) => s[0].toUpperCase() + s.slice(1)).join('');
  }
  return cleaned[0].toUpperCase() + cleaned.slice(1);
}

/** PascalCase enum-variant name from a free-form string. */
function toEnumVariant(value: string): string {
  const cleaned = value.replace(/[^a-zA-Z0-9]+/g, ' ').trim();
  return cleaned
    .split(' ')
    .filter(Boolean)
    .map((w) => w[0].toUpperCase() + w.slice(1))
    .join('');
}

// ─── Type Mapping ────────────────────────────────────────────────────────────

const requiredPartialStructs = new Set<string>();

function partialCsName(tsInterfaceName: string): string {
  return `Partial${stripIPrefix(tsInterfaceName)}`;
}

/** Map a TypeScript type expression to a C# type expression (no nullability). */
function mapType(tsType: string): string {
  tsType = tsType.replace(/import\([^)]+\)\./g, '').trim();

  while (tsType.startsWith('(') && tsType.endsWith(')')) {
    tsType = tsType.slice(1, -1).trim();
  }

  if (tsType === 'string') return 'string';
  if (tsType === 'number') return 'long';
  if (tsType === 'boolean') return 'bool';
  if (tsType === 'unknown') return 'JsonElement';
  if (tsType === 'object') return 'JsonElement';
  if (tsType === 'true' || tsType === 'false') return 'bool';

  if (tsType === 'URI') return 'string';
  if (tsType === 'StringOrMarkdown') return 'StringOrMarkdown';

  // ChildCustomizationType is a TS-only subset alias of CustomizationType.
  if (tsType === 'ChildCustomizationType') return 'CustomizationType';

  if (tsType === 'SessionStatus') return 'SessionStatus';

  if (
    tsType === 'IRootState | ISessionState' ||
    tsType === 'IRootState | ISessionState | ITerminalState' ||
    tsType === 'RootState | SessionState' ||
    tsType === 'RootState | SessionState | TerminalState' ||
    tsType === 'RootState | SessionState | TerminalState | ChangesetState'
  ) {
    return 'SnapshotState';
  }

  // `T | null` — handled at the property level (nullability); strip here.
  const nullMatch = tsType.match(/^(.+?)\s*\|\s*null$/);
  if (nullMatch) {
    return mapType(nullMatch[1]);
  }

  const undefMatch = tsType.match(/^(.+?)\s*\|\s*undefined$/);
  if (undefMatch) return mapType(undefMatch[1]);

  const arrayMatch = tsType.match(/^(.+)\[\]$/);
  if (arrayMatch) return `List<${mapType(arrayMatch[1])}>`;

  const arrayGenericMatch = tsType.match(/^Array<(.+)>$/);
  if (arrayGenericMatch) return `List<${mapType(arrayGenericMatch[1])}>`;

  const recordMatch = tsType.match(/^Record<string,\s*(.+)>$/);
  if (recordMatch) {
    const inner = recordMatch[1].trim();
    if (inner === 'unknown') return 'Dictionary<string, JsonElement>';
    return `Dictionary<string, ${mapType(inner)}>`;
  }

  const partialMatch = tsType.match(/^Partial<(\w+)>$/);
  if (partialMatch) {
    requiredPartialStructs.add(partialMatch[1]);
    return partialCsName(partialMatch[1]);
  }

  const enumUnionMatch = tsType.match(/^(\w+)\.\w+(\s*\|\s*\1\.\w+)*$/);
  if (enumUnionMatch) return stripIPrefix(enumUnionMatch[1]);

  const enumMemberMatch = tsType.match(/^(\w+)\.(\w+)$/);
  if (enumMemberMatch) return stripIPrefix(enumMemberMatch[1]);

  if (tsType.startsWith("'") && tsType.endsWith("'")) return 'string';
  if (/^'[^']*'(\s*\|\s*'[^']*')+$/.test(tsType)) return 'string';

  if (tsType.startsWith('{')) return 'JsonElement';

  return stripIPrefix(tsType);
}

// Value-type detection lives in `csIsValueType` below; it consults the
// `ALL_ENUM_NAMES` set so optional enum-typed properties get a `?`.

// ─── Property Extraction ─────────────────────────────────────────────────────

interface CsProp {
  csName: string;
  wireName: string;
  csType: string;
  optional: boolean;
  doc: string;
  isLiteralDiscriminant: boolean;
  literalValue?: string;
}

function getPropertyType(prop: PropertySignature): string {
  const typeNode = prop.getTypeNode();
  if (typeNode) return typeNode.getText();
  return prop.getType().getText(prop);
}

function getPropertyDoc(prop: PropertySignature): string {
  const jsDocs = prop.getJsDocs();
  if (jsDocs.length === 0) return '';
  return jsDocs[0].getDescription().trim();
}

function hasFormatFloat(prop: PropertySignature): boolean {
  for (const doc of prop.getJsDocs()) {
    for (const tag of doc.getTags()) {
      if (tag.getTagName() === 'format' && tag.getCommentText()?.trim() === 'float') {
        return true;
      }
    }
  }
  return false;
}

function getAllProperties(iface: InterfaceDeclaration, project: Project): PropertySignature[] {
  const props: PropertySignature[] = [];
  for (const ext of iface.getExtends()) {
    const baseName = ext.getExpression().getText();
    const baseIface = findInterface(project, baseName);
    if (baseIface) {
      props.push(...getAllProperties(baseIface, project));
    }
  }
  props.push(...iface.getProperties());
  return props;
}

function findInterface(project: Project, name: string): InterfaceDeclaration | undefined {
  for (const sf of project.getSourceFiles()) {
    const iface = sf.getInterface(name);
    if (iface) return iface;
  }
  return undefined;
}

function findEnum(project: Project, name: string): EnumDeclaration | undefined {
  for (const sf of project.getSourceFiles()) {
    const e = sf.getEnum(name);
    if (e) return e;
  }
  return undefined;
}

/** Names of every enum the generator emits (so optionals can nullable-ify value-type enums). */
const ALL_ENUM_NAMES = new Set<string>();

function extractProps(iface: InterfaceDeclaration, project: Project): CsProp[] {
  const allProps = getAllProperties(iface, project);
  const seen = new Set<string>();
  const result: CsProp[] = [];

  for (const p of allProps) {
    const tsName = p.getName();
    if (seen.has(tsName)) continue;
    seen.add(tsName);

    const tsType = getPropertyType(p);

    const enumMember = tsType.match(/^(\w+)\.(\w+)$/);
    const stringLiteral = tsType.match(/^'([^']+)'$/);
    let isLiteralDiscriminant = false;
    let literalValue: string | undefined;

    const tsPropLower = tsName.toLowerCase();
    if (['type', 'kind', 'status', 'state'].includes(tsPropLower)) {
      if (enumMember) {
        const enumName = enumMember[1];
        const memberName = enumMember[2];
        const enumDecl = findEnum(project, enumName);
        if (enumDecl) {
          const mem = enumDecl.getMembers().find((m) => m.getName() === memberName);
          if (mem) {
            isLiteralDiscriminant = true;
            literalValue = String(mem.getValue());
          }
        }
      } else if (stringLiteral) {
        isLiteralDiscriminant = true;
        literalValue = stringLiteral[1];
      } else if (/^\w+\.\w+(\s*\|\s*\w+\.\w+)+$/.test(tsType)) {
        isLiteralDiscriminant = true;
      }
    }

    const csName = csIdent(toPascalCase(tsName));
    const hasUnionUndefined = /\|\s*undefined/.test(tsType);
    const hasUnionNull = /\|\s*null/.test(tsType);
    const hasQuestionToken = p.hasQuestionToken();

    let csType = mapType(tsType);
    if (csType === 'long' && hasFormatFloat(p)) {
      csType = 'double';
    }

    const optional = hasQuestionToken || hasUnionUndefined || hasUnionNull;

    result.push({
      csName,
      wireName: tsName,
      csType,
      optional,
      doc: getPropertyDoc(p),
      isLiteralDiscriminant,
      literalValue,
    });
  }
  return result;
}

/** True when the C# type is a value type (primitive / JsonElement / known enum). */
function csIsValueType(csType: string): boolean {
  if (csType === 'long' || csType === 'double' || csType === 'bool' || csType === 'JsonElement') {
    return true;
  }
  return ALL_ENUM_NAMES.has(csType);
}

// ─── Doc Comments ────────────────────────────────────────────────────────────

function emitDocComment(prefix: string, doc: string | undefined, lines: string[]): void {
  if (!doc) return;
  const docLines = doc.split('\n').map((l) => l.trimEnd());
  // Trim trailing blank lines.
  while (docLines.length && docLines[docLines.length - 1] === '') docLines.pop();
  if (docLines.length === 0) return;
  lines.push(`${prefix}/// <summary>`);
  for (const line of docLines) {
    lines.push(`${prefix}/// ${escapeXmlDoc(line)}`.trimEnd());
  }
  lines.push(`${prefix}/// </summary>`);
}

function escapeXmlDoc(s: string): string {
  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

// ─── Enum Generation ─────────────────────────────────────────────────────────

/**
 * String enum:
 *   [JsonConverter(typeof(WireEnumConverter<PolicyState>))]
 *   public enum PolicyState { [WireValue("enabled")] Enabled, ... }
 */
function generateStringEnum(enumDecl: EnumDeclaration): string {
  const name = enumDecl.getName();
  const lines: string[] = [];
  emitDocComment('', enumDecl.getJsDocs()[0]?.getDescription().trim(), lines);
  lines.push(`[JsonConverter(typeof(WireEnumConverter<${name}>))]`);
  lines.push(`public enum ${name}`);
  lines.push('{');
  const members = enumDecl.getMembers();
  members.forEach((mem) => {
    const memberDoc = mem.getJsDocs()[0]?.getDescription().trim();
    emitDocComment('    ', memberDoc, lines);
    const wire = String(mem.getValue());
    lines.push(`    [WireValue(${JSON.stringify(wire)})]`);
    lines.push(`    ${mem.getName()},`);
  });
  lines.push('}');
  return lines.join('\n');
}

/**
 * Bitset enum (numeric values): [Flags] enum : uint. System.Text.Json
 * serializes enums as their numeric value by default, so unknown future
 * bits round-trip losslessly.
 */
function generateBitsetEnum(enumDecl: EnumDeclaration): string {
  const name = enumDecl.getName();
  const lines: string[] = [];
  emitDocComment('', enumDecl.getJsDocs()[0]?.getDescription().trim(), lines);
  lines.push('[Flags]');
  lines.push(`public enum ${name} : uint`);
  lines.push('{');
  for (const mem of enumDecl.getMembers()) {
    const memberDoc = mem.getJsDocs()[0]?.getDescription().trim();
    emitDocComment('    ', memberDoc, lines);
    lines.push(`    ${mem.getName()} = ${mem.getValue()},`);
  }
  lines.push('}');
  return lines.join('\n');
}

function generateEnum(enumDecl: EnumDeclaration): string {
  const values = enumDecl.getMembers().map((m) => m.getValue());
  const isNumeric = values.every((v) => typeof v === 'number');
  return isNumeric ? generateBitsetEnum(enumDecl) : generateStringEnum(enumDecl);
}

// ─── Struct Generation ───────────────────────────────────────────────────────

interface StructOpts {
  omitDiscriminants?: boolean;
  doc?: string;
  includeDiscriminants?: boolean;
}

/** True when the C# type is a generic collection the generator emits
 *  (`List<...>` / `Dictionary<...>`). A required-but-unset collection is
 *  modeled as null-forgiving (see {@link csPropDefault}). */
function csIsCollectionType(csType: string): boolean {
  return csType.startsWith('List<') || csType.startsWith('Dictionary<');
}

/**
 * True when a REQUIRED property is a nested object — i.e. a reference type that
 * is neither a string, a StringOrMarkdown wrapper, a value type/enum, nor a
 * generic collection. The schema marks these `required`, so the C# field must
 * be non-nullable AND enforced on decode. We model that with the C# `required`
 * modifier (see {@link csRequiredModifier}) rather than a null-forgiving
 * default, so a wire payload omitting the field is rejected — matching the
 * schema's `required` array (e.g. SessionAddedParams.summary). Collections keep
 * the null-forgiving default because a null collection serializes as `null`,
 * which the conformance harness strips (matching Go's nil slice/map).
 */
function csIsRequiredNestedObject(csType: string, optional: boolean): boolean {
  if (optional) return false;
  if (csIsValueType(csType)) return false;
  if (csType === 'string' || csType === 'StringOrMarkdown') return false;
  if (csIsCollectionType(csType)) return false;
  return true;
}

/** The `required ` modifier (with trailing space) for properties that must be
 *  set, else the empty string. */
function csRequiredModifier(csType: string, optional: boolean): string {
  return csIsRequiredNestedObject(csType, optional) ? 'required ' : '';
}

function csPropDefault(csType: string, optional: boolean): string {
  if (optional) return '';
  // Required value types get the C# default (matches Go's numeric/bool zero).
  if (csIsValueType(csType)) return '';
  // Required string → "" (matches Go's string zero value, which serializes
  // as "" rather than null).
  if (csType === 'string') return ' = "";';
  // Required StringOrMarkdown → empty wrapper, which serializes as "" (matches
  // Go's value-type zero).
  if (csType === 'StringOrMarkdown') return ' = new();';
  // Required nested objects use the `required` modifier (no default) so a wire
  // payload missing the field is rejected, matching the schema's `required`
  // array. csRequiredModifier emits the keyword; no initializer is needed.
  if (csIsRequiredNestedObject(csType, optional)) return '';
  // Required collections → null-forgiving. A null collection serializes as
  // `null`, which the conformance harness strips — matching Go, where a
  // required-but-unset slice/map is `nil` → `null`. Deserialization and
  // reducers populate these before they are read.
  return ' = null!;';
}

function generateCsClass(csName: string, props: CsProp[], opts: StructOpts = {}): string {
  const lines: string[] = [];
  emitDocComment('', opts.doc, lines);
  const include = opts.includeDiscriminants === true;
  const emittedProps = props.filter(
    (p) => include || !(opts.omitDiscriminants && p.isLiteralDiscriminant),
  );

  lines.push(`public sealed class ${csName}`);
  lines.push('{');
  emittedProps.forEach((p, idx) => {
    if (idx > 0) lines.push('');
    if (p.doc) emitDocComment('    ', p.doc, lines);
    lines.push(`    [JsonPropertyName(${JSON.stringify(p.wireName)})]`);
    let csType = p.csType;
    if (p.optional) {
      lines.push('    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]');
      csType = `${csType}?`;
    }
    const def = csPropDefault(p.csType, p.optional);
    const req = csRequiredModifier(p.csType, p.optional);
    lines.push(`    public ${req}${csType} ${p.csName} { get; set; }${def}`);
  });
  lines.push('}');
  return lines.join('\n');
}

function generateClassFromInterface(
  project: Project,
  tsInterfaceName: string,
  csNameOverride?: string,
  opts: StructOpts = {},
): string {
  const iface = findInterface(project, tsInterfaceName);
  if (!iface) throw new Error(`Interface ${tsInterfaceName} not found`);
  const name = csNameOverride ?? stripIPrefix(tsInterfaceName);
  const props = extractProps(iface, project);
  const ifaceDoc = iface.getJsDocs()[0]?.getDescription().trim();
  return generateCsClass(name, props, { doc: ifaceDoc, ...opts });
}

function generatePartialClass(project: Project, tsInterfaceName: string): string {
  const iface = findInterface(project, tsInterfaceName);
  if (!iface) throw new Error(`Interface ${tsInterfaceName} not found`);
  const props = extractProps(iface, project).map((p) => ({ ...p, optional: true }));
  return generateCsClass(partialCsName(tsInterfaceName), props, {
    doc: `Partial equivalent of ${stripIPrefix(tsInterfaceName)} — every field is optional for delta updates.`,
  });
}

// ─── Discriminated Union Generation ──────────────────────────────────────────

interface UnionVariant {
  variantName: string;
  innerType: string;
  wireValue: string;
  doc?: string;
}

interface UnionConfig {
  name: string;
  discriminantField: string;
  doc?: string;
  variants: UnionVariant[];
  unknown?: boolean;
}

function generateDiscriminatedUnion(cfg: UnionConfig): string {
  const lines: string[] = [];
  emitDocComment('', cfg.doc, lines);
  lines.push(`[JsonConverter(typeof(${cfg.name}Converter))]`);
  lines.push(`public sealed class ${cfg.name} : AhpUnion`);
  lines.push('{');
  lines.push(`    /// <summary>Creates an empty ${cfg.name} (no active variant).</summary>`);
  lines.push(`    public ${cfg.name}() { }`);
  lines.push('');
  lines.push(`    /// <summary>Creates a ${cfg.name} wrapping the given variant value.</summary>`);
  lines.push(`    public ${cfg.name}(object? value) : base(value) { }`);
  lines.push('}');
  lines.push('');

  // Converter
  const entries = cfg.variants
    .map((v) => `        [${JSON.stringify(v.wireValue)}] = typeof(${v.innerType}),`)
    .join('\n');
  lines.push(
    `/// <summary>System.Text.Json converter for the ${cfg.name} discriminated union.</summary>`,
  );
  lines.push(`internal sealed class ${cfg.name}Converter : UnionConverter<${cfg.name}>`);
  lines.push('{');
  lines.push(`    public ${cfg.name}Converter()`);
  lines.push(`        : base(`);
  lines.push(`            discriminator: ${JSON.stringify(cfg.discriminantField)},`);
  lines.push(`            variants: new Dictionary<string, Type>`);
  lines.push('            {');
  lines.push(entries);
  lines.push('            },');
  lines.push(`            allowUnknown: ${cfg.unknown ? 'true' : 'false'})`);
  lines.push('    {');
  lines.push('    }');
  lines.push('}');
  return lines.join('\n');
}

