function generateMergedToolCallConfirmedClass(): string {
  return `/// <summary>
/// SessionToolCallConfirmedAction — the client approves or denies a
/// pending tool call (merged approved + denied variants on the wire).
/// </summary>
public sealed class SessionToolCallConfirmedAction
{
    [JsonPropertyName("type")]
    public ActionType Type { get; set; }

    [JsonPropertyName("turnId")]
    public string TurnId { get; set; } = "";

    [JsonPropertyName("toolCallId")]
    public string ToolCallId { get; set; } = "";

    [JsonPropertyName("_meta")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Meta { get; set; }

    [JsonPropertyName("approved")]
    public bool Approved { get; set; }

    [JsonPropertyName("confirmed")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ToolCallConfirmationReason? Confirmed { get; set; }

    [JsonPropertyName("reason")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ToolCallCancellationReason? Reason { get; set; }

    [JsonPropertyName("editedToolInput")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? EditedToolInput { get; set; }

    [JsonPropertyName("userSuggestion")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Message? UserSuggestion { get; set; }

    [JsonPropertyName("reasonMessage")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public StringOrMarkdown? ReasonMessage { get; set; }

    [JsonPropertyName("selectedOptionId")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? SelectedOptionId { get; set; }
}`;
}

function generateActionEnvelope(): string {
  return `/// <summary>
/// ActionEnvelope wraps every action with the channel URI it belongs to,
/// the server-assigned monotonic sequence number, and an optional origin.
/// </summary>
public sealed class ActionEnvelope
{
    [JsonPropertyName("channel")]
    public string Channel { get; set; } = "";

    [JsonPropertyName("action")]
    public StateAction Action { get; set; } = new();

    [JsonPropertyName("serverSeq")]
    public long ServerSeq { get; set; }

    [JsonPropertyName("origin")]
    public ActionOrigin? Origin { get; set; }

    [JsonPropertyName("rejectionReason")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? RejectionReason { get; set; }
}`;
}

function generateActionsUnion(): string {
  const cfg: UnionConfig = {
    name: 'StateAction',
    discriminantField: 'type',
    doc: 'StateAction is the discriminated union of every state action.',
    variants: ACTION_VARIANTS.map((v) => ({
      variantName: v.variantName,
      innerType: v.tsInterface === '_merged_' ? 'SessionToolCallConfirmedAction' : stripIPrefix(v.tsInterface),
      wireValue: v.type,
    })),
    unknown: true,
  };
  return generateDiscriminatedUnion(cfg);
}

function generateActionsFile(project: Project): string {
  const lines: string[] = [fileHeader()];

  lines.push('// ─── ActionType ──────────────────────────────────────────────────────\n');
  const actionTypeEnum = findEnum(project, 'ActionType');
  lines.push(actionTypeEnum ? generateEnum(actionTypeEnum) : '// TODO: ActionType enum not found');
  lines.push('');

  lines.push('// ─── Action Envelope ─────────────────────────────────────────────────\n');
  lines.push(generateClassFromInterface(project, 'ActionOrigin'));
  lines.push('');
  lines.push(generateActionEnvelope());
  lines.push('');

  lines.push('// ─── Action Payloads ─────────────────────────────────────────────────\n');
  for (const v of ACTION_VARIANTS) {
    if (v.tsInterface === '_merged_') {
      lines.push(generateMergedToolCallConfirmedClass());
      lines.push('');
      continue;
    }
    try {
      lines.push(generateClassFromInterface(project, v.tsInterface, undefined, { includeDiscriminants: true }));
      lines.push('');
    } catch (e) {
      lines.push(`// TODO: could not generate ${v.tsInterface}: ${e}`);
      lines.push('');
    }
  }

  lines.push('// ─── StateAction Union ───────────────────────────────────────────────\n');
  lines.push(generateActionsUnion());
  lines.push('');

  return lines.join('\n');
}

